export const 鎮宅凶殃 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿二（左端迴鉤）＋散圈叢＋長桁
    線(p => p.M(X(0.4), Z(1.3)).C(X(0.3), Z(0.9), X(0.6), Z(0.8), X(1.0), Z(0.95))
        .L(X(7.3), Z(0.9)));
    線(p => p.M(X(0.8), Z(2.1)).L(X(6.6), Z(2.0)));
    圈(6.9, 2.0);
    for (const [x, z] of [[0.6, 3.3], [1.2, 3.7], [4.3, 3.4], [6.9, 3.4],
        [0.7, 4.5], [1.3, 4.9], [2.5, 4.6], [4.3, 4.7], [6.8, 4.8]])
        圈(x, z);
    線(p => p.M(X(0.4), Z(6.4)).L(X(7.1), Z(6.3)), 0.42);
    // 符身：頂桁
    線(p => p.M(X(0.8), Z(7.4)).L(X(7.0), Z(7.3)), 0.42);
    // 左山迴（蛇帶boustro三折）
    線(p => p.M(X(0.6), Z(7.6)).L(X(0.6), Z(10.3))
        .C(X(0.6), Z(10.7), X(0.9), Z(10.9), X(1.4), Z(10.9))
        .C(X(1.9), Z(10.9), X(2.2), Z(10.6), X(2.2), Z(10.1))
        .L(X(2.2), Z(8.6)).C(X(2.2), Z(8.2), X(2.5), Z(8.0), X(2.9), Z(8.0))
        .C(X(3.4), Z(8.0), X(3.6), Z(8.3), X(3.6), Z(8.8))
        .L(X(3.6), Z(10.9)));
    // 右冂雙軌內U
    線(p => p.M(X(5.6), Z(7.6)).L(X(5.6), Z(11.0)));
    線(p => p.M(X(6.9), Z(7.6)).L(X(6.9), Z(11.2)));
    線(p => p.M(X(6.0), Z(8.2)).L(X(6.0), Z(9.8))
        .C(X(6.0), Z(10.3), X(6.5), Z(10.3), X(6.5), Z(9.8)).L(X(6.5), Z(8.2)));
    // 中日箱十字
    線(p => p.M(X(1.9), Z(11.6)).L(X(1.9), Z(14.5)).L(X(3.6), Z(14.4))
        .L(X(3.6), Z(11.5)).L(X(1.85), Z(11.6)));
    線(p => p.M(X(2.0), Z(13.0)).L(X(3.5), Z(12.9)));
    線(p => p.M(X(2.75), Z(11.7)).L(X(2.7), Z(14.4)));
    // 右軌續落
    線(p => p.M(X(5.0), Z(11.5)).L(X(5.0), Z(16.2)));
    線(p => p.M(X(6.2), Z(11.6)).L(X(6.2), Z(16.0)));
    // 底匚曲（左匚＋右軌迴脚）
    線(p => p.M(X(0.5), Z(15.6)).L(X(0.5), Z(17.3)).L(X(3.5), Z(17.2))
        .L(X(3.5), Z(15.7)));
    線(p => p.M(X(1.5), Z(16.4)).L(X(3.4), Z(16.3)));
    線(p => p.M(X(5.0), Z(16.15)).C(X(4.9), Z(17.2), X(5.2), Z(17.9), X(5.9), Z(18.0)));
    線(p => p.M(X(6.2), Z(15.95)).C(X(6.4), Z(17.0), X(6.6), Z(17.7), X(6.3), Z(18.2)));
};
